window.__QUIZ_DATA__=[{"id":"theory>Economics>2021>1>a","subject":"Economics","year":"2021","type":"Theory","sub_label":"a","group":"FINAL","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t    Calculate the size of the entire labour force in the country","images":[],"marking_scheme":"Size of the labour force = 30+37+19+12.2+16.1+10.8+15.6+19+10.3   = 170million","marks":"3","difficulty":"3"},{"id":"theory>Economics>2021>1>b>i","subject":"Economics","year":"2021","type":"Theory","sub_label":"i","group":"FINAL","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t    What percentage of the labour force is engaged in the:   - Primary sector","images":[],"marking_scheme":"Primary sector = Mining +Fish farming +Food crop production   = 16.1 + 10.8 + 15.6)/170 x 100   = 25%","marks":"3","difficulty":"3"},{"id":"theory>Economics>2021>1>b>ii","subject":"Economics","year":"2021","type":"Theory","sub_label":"ii","group":"FINAL","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t   What percentage of the labour force is engaged in the:   - secondary sector","images":[],"marking_scheme":"Secondary sector = Shoe production + Fish Processing + Baking   = (30 + 19+19)/170 x 100   = 40%","marks":"3","difficulty":"3"},{"id":"theory>Economics>2021>1>b>iii","subject":"Economics","year":"2021","type":"Theory","sub_label":"iii","group":"FINAL","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t   What percentage of the labour force is engaged in the:   - tertiary sector","images":[],"marking_scheme":"Tertiary production = Banking + Warehousing +Laundry   = 37 + 12.2 + 10.3   = 59.5/170 x 100   = 35%","marks":"3","difficulty":"3"},{"id":"theory>Economics>2021>1>c","subject":"Economics","year":"2021","type":"Theory","sub_label":"c","group":"FINAL","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t    Calculate the ratio of the workers in mining to the workers in shoe production","images":[],"marking_scheme":"Ratio =Mining/shoe production     = 16.1 /30     = 16.1:30","marks":"2","difficulty":"3"},{"id":"theory>Economics>2021>1>d","subject":"Economics","year":"2021","type":"Theory","sub_label":"d","group":"FINAL","topic":"POPULATION : DETERMINANTS OF POPULATION SIZE","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t   Calculate the percentage of the people engaged in warehousing","images":[],"marking_scheme":"Warehousing = 12.2/170 x 100   = 7.2%","marks":"3","difficulty":"3"},{"id":"theory>Economics>2021>1>e>i","subject":"Economics","year":"2021","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t    Identify the type of economy depicted in the table","images":[],"marking_scheme":"The type of economy depicted is Mixed economy","marks":"1","difficulty":"2"},{"id":"theory>Economics>2021>1>e>ii","subject":"Economics","year":"2021","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM","question":"Table  below shows the distribution of the population of a country in various occupation. Study it and answer the questions that follow.     Table   OCCUPATION\tTOTAL\tShoe production\t30 million\tBanking\t37million\tFish processing\t19million\tWarehousing\t12.2 million\tMining\t16.1 million\tFish farming\t10.8 million\tFood crop production\t15.6 million\tBaking\t19 million\tLaundry\t10.3 million\t   - Give a reason for your answer in 1(e)(i)","images":[],"marking_scheme":"In a mixed economy, there is a combination of different sectors such as agriculture (food crop production, fish farming), manufacturing (shoe production, fish processing, baking), and services (banking, warehousing, laundry). The presence of diverse occupations indicates that the economy has both private and public sector involvement in various industries. This mix of primary (like mining and farming), secondary (like production and processing), and tertiary (like banking and warehousing) activities reflects a balanced economic structure typical of a mixed economy.","marks":"2","difficulty":"2"},{"id":"theory>Economics>2021>2>a","subject":"Economics","year":"2021","type":"Theory","sub_label":"a","group":"","topic":"THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE","question":"Table 2 below shows the unit prices and quantities of hats produced bu a firm. Study it and answer the questions that follow:     Table 2   Quantity\tUnit Price($)\tTotal Revenue($)\tMarginal Revenue($)\tAverage Revenue($)\t10\t180\t1800\t-\t180\t20\t150\t3000\t120\tX\t30\tU\t3600\t60\t120\t40\t100\tV\tW\tY\t50\t80\t4000\t0\t80\t60\t60\t3600\t-40\t60\t    Complete the values of U,V,W and Y","images":[],"marking_scheme":"U : Unit price = TR/Q   = 3600/30   = $120     V: Total revenue = Price x quantity   = 100 x 40   $4,000     W: Marginal revenue = \u2206TR/\u2206Q   = 4000 - 3600/ 40 -30   = 400/10   = $40     X: Average revenue: TR/Q   = 3000/20   = $150     Y: Average revenue: TR/Q   = 4000/40   = $100","marks":"10","difficulty":"3"},{"id":"theory>Economics>2021>2>b","subject":"Economics","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MARKET STRUCTURE : FORMS OF MARKET STRUCTURE","question":"Table 2 below shows the unit prices and quantities of hats produced bu a firm. Study it and answer the questions that follow:     Table 2   Quantity\tUnit Price($)\tTotal Revenue($)\tMarginal Revenue($)\tAverage Revenue($)\t10\t180\t1800\t-\t180\t20\t150\t3000\t120\tX\t30\tU\t3600\t60\t120\t40\t100\tV\tW\tY\t50\t80\t4000\t0\t80\t60\t60\t3600\t-40\t60\t   In what type of market is the firm operating? Explain your answer","images":[],"marking_scheme":"Perfect competitive market. It is a perfect market because the average revenue is also the price and also the average revenue and the marginal revenue for the firms are equal to the product's price to the buyer.","marks":"3","difficulty":"2"},{"id":"theory>Economics>2021>2>c","subject":"Economics","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM","question":"Table 2 below shows the unit prices and quantities of hats produced bu a firm. Study it and answer the questions that follow:     Table 2   Quantity\tUnit Price($)\tTotal Revenue($)\tMarginal Revenue($)\tAverage Revenue($)\t10\t180\t1800\t-\t180\t20\t150\t3000\t120\tX\t30\tU\t3600\t60\t120\t40\t100\tV\tW\tY\t50\t80\t4000\t0\t80\t60\t60\t3600\t-40\t60\t   If the firm's marginal cost is $60.00 at all level of outputs, at what level of output will it be in equilibrium? Explain your answer.","images":[],"marking_scheme":"The firm will be at equilibrium at output 30. The firm is at equilibrium when the Marginal Revenue is equal to the Marginal Cost i.e MR = MC","marks":"3","difficulty":"3"},{"id":"theory>Economics>2021>2>d","subject":"Economics","year":"2021","type":"Theory","sub_label":"d","group":"FINAL","topic":"THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM","question":"Table 2 below shows the unit prices and quantities of hats produced bu a firm. Study it and answer the questions that follow:     Table 2   Quantity\tUnit Price($)\tTotal Revenue($)\tMarginal Revenue($)\tAverage Revenue($)\t10\t180\t1800\t-\t180\t20\t150\t3000\t120\tX\t30\tU\t3600\t60\t120\t40\t100\tV\tW\tY\t50\t80\t4000\t0\t80\t60\t60\t3600\t-40\t60\t   If a total cost of $600.00 is incurred when 50 units of hats are produced, determine the margin of profit or loss made","images":[],"marking_scheme":"At 50 units   Total cost =$600   Total revenue =$4,000   Since the total revenue is higher than the total cost, then there will be profit   Profit = TR - TC   = 4000 - 600   = $3,400","marks":"3","difficulty":"3"},{"id":"theory>Economics>2021>2>e","subject":"Economics","year":"2021","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION","question":"Table 2 below shows the unit prices and quantities of hats produced bu a firm. Study it and answer the questions that follow:     Table 2   Quantity\tUnit Price($)\tTotal Revenue($)\tMarginal Revenue($)\tAverage Revenue($)\t10\t180\t1800\t-\t180\t20\t150\t3000\t120\tX\t30\tU\t3600\t60\t120\t40\t100\tV\tW\tY\t50\t80\t4000\t0\t80\t60\t60\t3600\t-40\t60\t   What is another name for marginal cost?","images":[],"marking_scheme":"Marginal cost is also known as incremental cost, extra cost.","marks":"1","difficulty":"1"},{"id":"theory>Economics>2021>3>a","subject":"Economics","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION","question":"What is economic of scale?","images":[],"marking_scheme":"Economics of scale is the amount of factors used, the quantities of product produced and the techniques of production adopted by a producer. It is also known as scale of production.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2021>3>b","subject":"Economics","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION","question":"Outline three internal economies of scale a firm can enjoy","images":[],"marking_scheme":"- Technical economies: In large scale of production, huge and modern machines are used and production increased with a little increase in costs     - Managerial economies: Managerial specialization is also possible when the scale of production is large. Increased production, the marginal costs are distributed over a wide range     - Financial economies: These are large firms which have a market reputation due to their assets and properties and volume of production.","marks":"9","difficulty":"2"},{"id":"theory>Economics>2021>3>c","subject":"Economics","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION","question":"Question:  State three factors that can influence where a firm is sited","images":[],"marking_scheme":"- Nearness to market  - Workforce   - Transport availability  - Availability of power  - Nearness to source of raw materials","marks":"9","difficulty":"2"},{"id":"theory>Economics>2021>4>a","subject":"Economics","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"DISTRIBUTIVE TRADE : THE RETAILER","question":"Define produt retailing","images":[],"marking_scheme":"Product retailing is the process when the dealing are based on tangible goods and usually a relationship with the buyer develops overtime when the buyer visits the product retailer frequently over a period of time.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2021>4>b","subject":"Economics","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"DISTRIBUTIVE TRADE : THE WHOLESALER","question":"Outline any three roles performed by the wholesaler to the manufacturer","images":[],"marking_scheme":"- Breaking of bulk: The wholesaler serves as a bulk breaker to the manufacturer to enable the retailer buy the goods.     - Price stability: They help to prevent price fluctuation by stocking the goods until they are demanded     - Information dissemination: Since the wholesaler is more closer to the retailers and the consumers, he knows what they want and the complaints that has been made on the goods of the manufacturer.","marks":"9","difficulty":"2"},{"id":"theory>Economics>2021>4>c","subject":"Economics","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"DISTRIBUTIVE TRADE : INTRODUCTION","question":"Identity any three problems associated with distribution of products","images":[],"marking_scheme":"- Packaging problems: The packaging of goods is not standardized. This may result in damage or ooss in transit     - indequate transport facilities: The poor transport system also affect commodity distribution and marketing in the country. The roads are so bad that commodities sustain great change due to accidents     - Long chain of distribution: There are too many middlemen. The numerous limks along the chain of distribution make the price of commodities to increase considerably.","marks":"9","difficulty":"2"},{"id":"theory>Economics>2021>5>a","subject":"Economics","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Define price elasticity of demand","images":[],"marking_scheme":"Price elasticity of demand can be defined as the degree of resposivness of a change in quantity demanded to change in price of a commodity. It is always negative and it id calculated as:   e = \u2206Qd/\u2206P x P/Qd   OR   e = percentage change in qd/ percentage change in p","marks":"2","difficulty":"1"},{"id":"theory>Economics>2021>5>b","subject":"Economics","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Distinguishing between elastic demand and inelastic demand","images":[],"marking_scheme":"Elastic demand is also known as fairly elastic demand. Demand is said to be elastic when a small change in price leads to a greater change in the quantity demanded. Elastic demand is greater than one.     Inelastic demand is also known as fairly inelastic demand. Demand is said to be inelastic when a larger change in price leads to a smaller change in the quantity demanded. Inelastic demand is less than one.","marks":"4","difficulty":"2"},{"id":"theory>Economics>2021>5>c>i","subject":"Economics","year":"2021","type":"Theory","sub_label":"i","group":"","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Using diagrams, explain what happens to a trader's total revenue when his price falls given that demand for his product is:    -  elastic","images":["data:image/png;base64,"],"marking_scheme":"If the demand is elastic, a decrease in price will result to an increase in the total revenue.         From the diagram above, the price falls from P1 to P2 while the quantity demanded increases from Q1 to Q2. Therefore as the quantity increases, the revenue og the trader will also increase.","marks":"7","difficulty":"3"},{"id":"theory>Economics>2021>5>c>ii","subject":"Economics","year":"2021","type":"Theory","sub_label":"ii","group":"","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Using diagrams, explain what happens to a trader's total revenue when his price falls given that demand for his product is:      inelastic","images":["data:image/png;base64,"],"marking_scheme":"If the demand for the product is inelastic, a fall in the price will reduce the total revenue of the trader.     From the diagram above, the price falls from P2 to P1 while the quantity demanded also decreases from Q2 to Q1. Therefore, as the quantity of the trader falls, the total revenue will also fall.","marks":"7","difficulty":"3"},{"id":"theory>Economics>2021>6>a","subject":"Economics","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"State three characteristics of perfect competition","images":[],"marking_scheme":"- There is free entry and exit   - The product are homogeneous   - There is perfect knowledge about the product   - There are large numbers of buyers and sellers   - The aim is to make profit","marks":"6","difficulty":"2"},{"id":"theory>Economics>2021>6>b>i","subject":"Economics","year":"2021","type":"Theory","sub_label":"i","group":"","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"With the aid of diagram, explain the equilibrium positions of a perfectly competitve firm in the:    Short run","images":["data:image/png;base64,"],"marking_scheme":"The short run is a period of time in which some factors are fixed and some are variable. In the short run, a perfect market enjoys increasing returns to scale.        From the diagram above, he is faced with average revenue horizontal demand curve or price line. Since the MR and AR are equal and there is no selling cost.   He sells at equilibrium price OP and equilibrium quantity OQ. His total revenue is OPMQ while total cost is OTSQ and earns abnormal profit represented by PMST as shaded in the diagram above.   However, the equilibrium position of the firm is at \"e\" where SMC cuts the MR from below.","marks":"7","difficulty":"3"},{"id":"theory>Economics>2021>6>b>ii","subject":"Economics","year":"2021","type":"Theory","sub_label":"ii","group":"","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"With the aid of diagram, explain the equilibrium positions of a perfectly competitve firm in the:      Long run","images":["data:image/png;base64,"],"marking_scheme":"The long run is a preriod of time in which all factors are completely variable. In the long run, the firm will be making only normal profit. Abnornal profit will be completely wipped off since new firms will enter the industry.      The firm will be in long run equilibrium when:   - when LMC =LMR=LAC=LAR=P=D   - when LMC cuts LMR from below   From the diagram above, the firm is at equilibrium at point \"e\" where the LRMC cuts the LRMR from below.","marks":"7","difficulty":"3"},{"id":"theory>Economics>2021>7>a>i","subject":"Economics","year":"2021","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"FINANCIAL INSTITUTION : CENTRAL BANK","question":"Explain how the Central Bank controls money supply through the use of:    Open market operations","images":[],"marking_scheme":"Open market Operation is the purchase or sale of government securities in the open market to expand or restrict the volume of money in circulation. When there is too much money in circulation, the central bank will sell securities but in order to expand the volume, it will buy securities.","marks":"4","difficulty":"3"},{"id":"theory>Economics>2021>7>a>ii","subject":"Economics","year":"2021","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"FINANCIAL INSTITUTION : CENTRAL BANK","question":"Explain how the Central Bank controls money supply through the use of:      bank rate","images":[],"marking_scheme":"Bank rate is the minimum rate of interest charged by the central bank for discounting bill of exchange. By lowering or raising the rate, the central bank can control the activities of the commercial banks. When the rate increases, loan to the public(customers)reduces, while a fall in the rate will encourage more loans.","marks":"4","difficulty":"3"},{"id":"theory>Economics>2021>7>b","subject":"Economics","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"FINANCIAL INSTITUTION : CENTRAL BANK","question":"Outline four functions performed by the Central Bank of your country","images":[],"marking_scheme":"-Bankers to the government: Central bank is an agent and banker to the government. It controls public account, receives revenue on behalf of the government amd makes payment from this account. Cental bank also obtains loans on behalf of the government.     - Issuance and control currency: The Central bank has the right to order the printing of the currency and issuance of it. It controls the circulation of currency, exchange of bad notes for new ones, and sees to the destruction of the bad notes.     - Bankers bank: The central bank acts as banker to the banks buy ensuring that the banks open accounts with it in order to facilitate clearng of cheques. This helps the commercial banks to have similar facilitites to offer to their customer.     - Lender of last resort: The central bank has a duty to assist the banking system when the banks are in financial difficulties so that they can withstand the strian of excessive demands.","marks":"12","difficulty":"2"},{"id":"theory>Economics>2021>8>a","subject":"Economics","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTERNATIONAL TRADE : INTRODUCTION","question":"Distinguish between domestic trade and external trade","images":[],"marking_scheme":"Domestic trade is also known as home trade. It is refers to the exchange of goods or services within a country or teritorry. In this type of trade scenerio, the market is constrianed by the borders of that country.     External trade is also known as foreign trade. It refers to the buying and selling og goods across national boundries of different countries. On the basis of sales and purchases of goods and services.","marks":"4","difficulty":"2"},{"id":"theory>Economics>2021>8>b","subject":"Economics","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"INTERNATIONAL TRADE : TERMS OF TRADE~~INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT","question":"Distinguish between terms of trade and balance of trade","images":[],"marking_scheme":"Terms of trade is the ratio between the index of export prices and the index of import prices. If the export prices increase more than the import prices, a country has a positive terms of trade, as for the same amount of export, it can purchase more imports.     Balance of trade is the difference between the value of a country's exports and the value of a country's imports for a given period.","marks":"4","difficulty":"2"},{"id":"theory>Economics>2021>8>c","subject":"Economics","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT","question":"Outline four causes of balance of payments deficit in a country","images":[],"marking_scheme":"- Rapid economic development: High outflow of foreign exchange to meet import demands like technology, machines and equipment can lead to balance of payment deficit.     - Inflation: Sustained rise in a country's prices can often make foreign products cheaper, leading to a high volume of imports.     - Political disturbance: Unstable tax structures, change in government, etc can lead to a loss in foreign investment, and give way for balance of payment deficit.     - Demonstration effect: Most of the developing countries get influenced by developed nations and start adopting the foreign pattern of consumption. In other words, this results in a sharp rise in imports leading to a deficit in the balance of payment.","marks":"12","difficulty":"3"}];